import{_ as a,o as e,c as i,ak as t}from"./chunks/framework.DvrM7GBU.js";const k=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":0}'),n={name:"getting-started/index.md"};function l(r,s,h,p,d,o){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting Started”">​</a></h1><p>Terror Server runs as a single Go binary and is usually installed as a systemd-managed service. The normal production flow is:</p><ol><li>Install the latest stable release.</li><li>Edit <code>/etc/terror/Runtime</code>.</li><li>Validate the config.</li><li>Let the systemd watcher restart <code>terror.service</code>.</li><li>Check route health with <code>terror status</code>.</li></ol><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to “Install”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://terror.softvenceomega.com/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><p>Then check the service:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terror</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The installer enables <code>terror.path</code>, a systemd path watcher. Saving <code>/etc/terror/Runtime</code> automatically triggers a service restart so new domains, removed routes, ports, and TLS listeners are picked up.</p></div><h2 id="your-first-runtime" tabindex="-1">Your First Runtime <a class="header-anchor" href="#your-first-runtime" aria-label="Permalink to “Your First Runtime”">​</a></h2><p>Open the Runtime file:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/terror/Runtime</span></span></code></pre></div><p>Start with a default static site and one proxied app:</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>:80 {</span></span>
<span class="line"><span>    root /var/www/terrorserver</span></span>
<span class="line"><span>    file_server</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>app.example.com {</span></span>
<span class="line"><span>    proxy localhost:4000</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Validate before saving a production change:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terror</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> validate</span></span></code></pre></div><p>After saving, confirm the route:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terror</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><h2 id="mental-model" tabindex="-1">Mental Model <a class="header-anchor" href="#mental-model" aria-label="Permalink to “Mental Model”">​</a></h2><p>Each Runtime block has an address and exactly one handler.</p><table tabindex="0"><thead><tr><th>Address type</th><th>Example</th><th>What it matches</th></tr></thead><tbody><tr><td>Domain</td><td><code>app.example.com</code></td><td>Requests with that hostname</td></tr><tr><td>Port</td><td><code>:9090</code></td><td>Any request received on that listener</td></tr></tbody></table><p>Each block chooses either <code>proxy</code> or <code>file_server</code>.</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>api.example.com {</span></span>
<span class="line"><span>    proxy localhost:3000</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docs.example.com {</span></span>
<span class="line"><span>    root /var/www/docs</span></span>
<span class="line"><span>    file_server</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li>Use <a href="/configuration/runtime">Runtime File</a> for all syntax rules.</li><li>Use <a href="/guides/reverse-proxy">Reverse Proxy</a> to publish local apps.</li><li>Use <a href="/guides/static-sites">Static Sites</a> for frontend builds and simple websites.</li><li>Use <a href="/guides/https-domains">HTTPS and Domains</a> before turning on forced redirects.</li></ul>`,24)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
